import{_ as d,o as a,c as r,a7 as e}from"./chunks/framework.C5fSpjcB.js";const m=JSON.parse('{"title":"Card List","description":"","frontmatter":{},"headers":[],"relativePath":"en/cards/list.md","filePath":"en/cards/list.md","lastUpdated":1775394001000}'),s={name:"en/cards/list.md"};function l(o,t,n,i,h,c){return a(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="card-list" tabindex="-1">Card List <a class="header-anchor" href="#card-list" aria-label="Permalink to &quot;Card List&quot;">​</a></h1><p>All cards in Morimens organized by Designated Realm. Card data available for 21 Awakeners so far.</p><h2 id="chaos-cards" tabindex="-1"><span class="realm-badge realm-chaos">Chaos</span> Cards <a class="header-anchor" href="#chaos-cards" aria-label="Permalink to &quot;&lt;span class=&quot;realm-badge realm-chaos&quot;&gt;Chaos&lt;/span&gt; Cards&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Card Name</th><th>Cost</th><th>Effect</th><th>Awakener</th></tr></thead><tbody><tr><td>Strike</td><td>1</td><td>标准打击卡</td><td>Alva</td></tr><tr><td>Combat Stance</td><td>1</td><td>获得防御力x10%护盾(4点)。回合结束时若在手中，获得的护盾提高2点。保留。 (启灵1后算力消耗-1(变为0费)，打出后驱散所有唤醒体封印状态)</td><td>Alva</td></tr><tr><td>Mind&#39;s Edge</td><td>3</td><td>造成攻击力x30%伤害(11点)。每点护盾使伤害提高2点。 (启灵3后，本回合每打出1张防御卡，心眼利刃算力消耗-1)</td><td>Alva</td></tr><tr><td><strong>Exalt</strong>: Endless Justice</td><td>—</td><td>获得19点护盾。弃掉手牌中所有状态卡和症状卡，并抽取等量+1的卡牌。</td><td>Alva</td></tr><tr><td><strong>Exalt</strong>: 狂气爆发</td><td>—</td><td>普通形态：回复生命并施加毒素。终章形态：失去生命，造成大量毒伤。每叠加一层终章，终章形态的伤害递增。</td><td>Doll</td></tr><tr><td><strong>Exalt</strong>: 狂气爆发</td><td>—</td><td>将上回合最后打出的3张固有指令卡的复制加入手牌，算力消耗-1。</td><td>Ramona: Timeworn</td></tr><tr><td>Strike</td><td>1</td><td>标准打击卡</td><td>Ramona</td></tr><tr><td>Defense</td><td>1</td><td>标准防御卡</td><td>Ramona</td></tr><tr><td>Assault Thesis</td><td>varies</td><td>拉蒙娜专属指令卡</td><td>Ramona</td></tr><tr><td>Queen&#39;s Sword</td><td>varies</td><td>拉蒙娜专属指令卡</td><td>Ramona</td></tr><tr><td>Wings Through Time</td><td>—</td><td>提供永久力量加成、狂气获取和力量窃取，附带12段伤害，配合回环更佳。双翼/四翼/六翼阶段可消耗钥能替代算力打出。</td><td>Tawil</td></tr><tr><td>Knowledge of All Things</td><td>—</td><td>占卜下一轮抽牌内容，补充狂气。</td><td>Tawil</td></tr><tr><td><strong>Exalt</strong>: 狂气爆发</td><td>—</td><td>从当前界域所有角色卡牌中五选三(附带消耗效果)，自带回环效果和保留机制。</td><td>Tawil</td></tr></tbody></table><h2 id="aequor-cards" tabindex="-1"><span class="realm-badge realm-aequor">Aequor</span> Cards <a class="header-anchor" href="#aequor-cards" aria-label="Permalink to &quot;&lt;span class=&quot;realm-badge realm-aequor&quot;&gt;Aequor&lt;/span&gt; Cards&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Card Name</th><th>Cost</th><th>Effect</th><th>Awakener</th></tr></thead><tbody><tr><td>Supreme Life Sacrifice</td><td>—</td><td>v1.4调整为穿透伤害。深海必备辅助技能，可为深海队提供触腕相关增益。 (v1.4版本升级调整：技能改为穿刺伤害类型)</td><td>Miryam</td></tr><tr><td>Strike</td><td>1</td><td>造成攻击力x10%伤害(4点)。图鲁获得5点狂气。</td><td>Tulu</td></tr><tr><td>Defense</td><td>1</td><td>获得防御力x10%护盾(4点)。图鲁获得5点狂气。</td><td>Tulu</td></tr><tr><td>Abyssal Command</td><td>4</td><td>对所有敌人造成攻击力x30%穿刺伤害(12点)。使所有触腕攻击1次，造成穿刺伤害。</td><td>Tulu</td></tr><tr><td>Spiral Annihilation Returns</td><td>3</td><td>驱散自身虚弱状态。临时触腕伤害+攻击力x20%(8点)。</td><td>Tulu</td></tr><tr><td><strong>Exalt</strong>: Hour of Stellar Alignment</td><td>—</td><td>获得1条触腕。临时触腕伤害+10。临时暴击率+25%。</td><td>Tulu</td></tr><tr><td>Strike</td><td>1</td><td>标准打击卡</td><td>Shan</td></tr><tr><td>Defense</td><td>1</td><td>获得防御力x10%护盾。打出佩戴者指令卡后，获得防御力x6%护盾；每条触腕额外获得防御力x1.5%护盾，每回合最多触发1次(来自命轮效果描述推导)。</td><td>Shan</td></tr></tbody></table><h2 id="caro-cards" tabindex="-1"><span class="realm-badge realm-caro">Caro</span> Cards <a class="header-anchor" href="#caro-cards" aria-label="Permalink to &quot;&lt;span class=&quot;realm-badge realm-caro&quot;&gt;Caro&lt;/span&gt; Cards&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Card Name</th><th>Cost</th><th>Effect</th><th>Awakener</th></tr></thead><tbody><tr><td>Strike</td><td>1</td><td>标准打击卡</td><td>Uvhash</td></tr><tr><td>Defense</td><td>1</td><td>标准防御卡</td><td>Uvhash</td></tr><tr><td>Scream, Blood!</td><td>0</td><td>失去20%当前生命值，造成15%体质(每级+1.5%)的群体伤害并获得6%体质(每级+0.6%)力量。升格4后每1%暴击伤害提高0.5%伤害和力量。 (启灵1后算力消耗-1(已为0费)，同时伤害和力量提高20%)</td><td>Uvhash</td></tr><tr><td>Boil, Blood!</td><td>0</td><td>自残类技能，压血手段之一</td><td>Uvhash</td></tr><tr><td><strong>Exalt</strong>: Exalt</td><td>—</td><td>造成150%体质(每级+15%)伤害，享受三倍力量增益。每次触发吞噬后，后续狂气爆发基础伤害提高1倍、力量增益提高1倍。</td><td>Uvhash</td></tr><tr><td><strong>Exalt</strong>: 狂气爆发</td><td>—</td><td>回复30%体质(每级+3%)生命值，获得15%体质(每级+1.5%)力量。当前每损失1%生命值，回复量提高2%。触发吞噬时回复量翻倍。血量最低时触发吞噬可回复1</td><td>Rhea</td></tr><tr><td>Strike</td><td>1</td><td>标准打击卡</td><td>Aigis</td></tr><tr><td>Defense</td><td>1</td><td>标准防御卡</td><td>Aigis</td></tr><tr><td>Chain Break Strike</td><td>—</td><td>血链·希洛的核心爆发技能，造成极高单次爆发伤害。配合环行·拉蒙娜的大招召回打击卡，实现「血希」队核心爆发。</td><td>Helot</td></tr></tbody></table><h2 id="ultra-cards" tabindex="-1"><span class="realm-badge realm-ultra">Ultra</span> Cards <a class="header-anchor" href="#ultra-cards" aria-label="Permalink to &quot;&lt;span class=&quot;realm-badge realm-ultra&quot;&gt;Ultra&lt;/span&gt; Cards&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Card Name</th><th>Cost</th><th>Effect</th><th>Awakener</th></tr></thead><tbody><tr><td><strong>Exalt</strong>: Electromagnetic Blast</td><td>—</td><td>强力输出大招，附带额外效果。</td><td>Erica</td></tr><tr><td>Strike</td><td>1</td><td>标准打击卡</td><td>Liz</td></tr><tr><td>Defense</td><td>1</td><td>获得7点护盾。跃迁：下回合开始前，每受到1次攻击，将1张具有消耗的「绿炎」置入手牌。保留。</td><td>Liz</td></tr><tr><td>Green Flame</td><td>0</td><td>对随机敌人造成6点穿刺伤害，施加50%伤害的中毒。回合结束时若在手牌或超维空间，升级为「腐化绿炎」。保留。</td><td>Liz</td></tr><tr><td><strong>Exalt</strong>: Dance of Death</td><td>—</td><td>获得临时2点力量，弃掉手牌中所有莉兹的卡片并触发它们的效果（免费打出所有绿炎）。</td><td>Liz</td></tr><tr><td><strong>Exalt</strong>: 狂气爆发</td><td>—</td><td>生成免费洞察力(Insight)，可用于恢复算力和额外抽牌。特定条件下创建千幻镜(Thousand Mirage)的定制复制。</td><td>Daffodil</td></tr><tr><td>Telekinesis</td><td>—</td><td>从超维空间拉出目标卡牌打出一次，配合达芙黛尔「断颈一击」实现二次打击。</td><td>Casiah</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Each Awakener has a set of Command Cards (typically 2-4 unique cards plus Strike/Defense), a Rouse (Awakening) card, and an Exalt (Fury Burst) card. Enlightenment upgrades are listed on individual Awakener pages.</p></div><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="./">Card System Overview</a></li><li><a href="./upgrade.html">Card Upgrades</a></li><li><a href="./deckbuilding.html">Deckbuilding Guide</a></li></ul>',13)])])}const g=d(s,[["render",l]]);export{m as __pageData,g as default};
